def validate_age(age):
    if age < 0 or age > 120:
        raise ValueError(f"age out of range: {age}")
    return age

for a in [30, -5, 200]:
    try:
        print(validate_age(a))
    except ValueError as err:
        print(err)

class OutOfStock(Exception):
    pass

def place_order(inventory, item, qty):
    if item not in inventory:
        raise KeyError(item)
    if inventory[item] < qty:
        raise OutOfStock(f"only {inventory[item]} left of {item}")
    return f"shipped {qty} {item}"

inventory = {"book": 5, "pen": 0}
orders = [("book", 2), ("pen", 1), ("hat", 1)]

for item, qty in orders:
    try:
        print(place_order(inventory, item, qty))
    except (KeyError, OutOfStock) as err:
        print(err)
